import threading
import queue
import time

class VideoStreamingThread(threading.Thread):
    def __init__(self, video_streaming_service, user_id, video_id):
        threading.Thread.__init__(self)
        self.video_streaming_service = video_streaming_service
        self.user_id = user_id
        self.video_id = video_id

    def run(self):
        while True:
            if self.video_streaming_service.users[self.user_id]['paused']:
                time.sleep(1)
                continue
            if self.video_streaming_service.get_playback_position(self.user_id) >= self.video_streaming_service.get_video_resolution(self.video_id):
                break
            self.video_streaming_service.skip_forward(self.user_id, 1)
            time.sleep(1)

class VideoStreamingServiceHandler:
    def __init__(self, video_streaming_service):
        self.video_streaming_service = video_streaming_service
        self.queue = queue.Queue()

    def handle_request(self, request):
        if request['type'] == 'play_video':
            self.video_streaming_service.play_video(request['user_id'], request['video_id'])
            thread = VideoStreamingThread(self.video_streaming_service, request['user_id'], request['video_id'])
            thread.start()
        elif request['type'] == 'pause_video':
            self.video_streaming_service.pause_video(request['user_id'])
        elif request['type'] == 'resume_video':
            self.video_streaming_service.resume_video(request['user_id'])
        elif request['type'] == 'skip_forward':
            self.video_streaming_service.skip_forward(request['user_id'], request['seconds'])
        elif request['type'] == 'skip_backward':
            self.video_streaming_service.skip_backward(request['user_id'], request['seconds'])

    def start(self):
        while True:
            request = self.queue.get()
            self.handle_request(request)
            self.queue.task_done()

