from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from werkzeug.utils import secure_filename
from threading import Lock

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///video.db'
db = SQLAlchemy(app)

class Video(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    title = db.Column(db.String(100), nullable=False)
    filename = db.Column(db.String(100), nullable=False)
    resolution = db.Column(db.String(20), nullable=False)
    size = db.Column(db.Integer, nullable=False)

    def __repr__(self):
        return f"Video('{self.title}', '{self.filename}', '{self.resolution}', {self.size})"

class VideoStreaming:
    def __init__(self):
        self.video_dict = {}
        self.lock = Lock()

    def add_video(self, video_id, video_file):
        with self.lock:
            self.video_dict[video_id] = video_file

    def get_video(self, video_id):
        with self.lock:
            return self.video_dict.get(video_id)

    def remove_video(self, video_id):
        with self.lock:
            if video_id in self.video_dict:
                del self.video_dict[video_id]

video_streaming = VideoStreaming()

@app.route('/upload_video', methods=['POST'])
def upload_video():
    if request.method == 'POST':
        video_file = request.files['video']
        filename = secure_filename(video_file.filename)
        video_file.save(os.path.join('videos', filename))
        video = Video(title=request.form['title'], filename=filename, resolution=request.form['resolution'], size=os.path.getsize(os.path.join('videos', filename)))
        db.session.add(video)
        db.session.commit()
        video_streaming.add_video(video.id, video_file)
        return jsonify({'message': 'Video uploaded successfully'}), 201

@app.route('/watch_video/<int:video_id>', methods=['GET'])
def watch_video(video_id):
    video = Video.query.get_or_404(video_id)
    video_file = video_streaming.get_video(video_id)
    if video_file:
        return jsonify({'video': video_file.read()}), 200
    else:
        return jsonify({'message': 'Video not found'}), 404

@app.route('/pause_video/<int:video_id>', methods=['POST'])
def pause_video(video_id):
    video = Video.query.get_or_404(video_id)
    video_file = video_streaming.get_video(video_id)
    if video_file:
        video_file.seek(0)
        return jsonify({'message': 'Video paused successfully'}), 200
    else:
        return jsonify({'message': 'Video not found'}), 404

@app.route('/restart_video/<int:video_id>', methods=['POST'])
def restart_video(video_id):
    video = Video.query.get_or_404(video_id)
    video_file = video_streaming.get_video(video_id)
    if video_file:
        video_file.seek(0)
        return jsonify({'message': 'Video restarted successfully'}), 200
    else:
        return jsonify({'message': 'Video not found'}), 404

@app.route('/skip_forwards/<int:video_id>/<int:seconds>', methods=['POST'])
def skip_forwards(video_id, seconds):
    video = Video.query.get_or_404(video_id)
    video_file = video_streaming.get_video(video_id)
    if video_file:
        video_file.seek(seconds)
        return jsonify({'message': 'Video skipped forwards successfully'}), 200
    else:
        return jsonify({'message': 'Video not found'}), 404

@app.route('/skip_backwards/<int:video_id>/<int:seconds>', methods=['POST'])
