import threading
import time

class ConnectionMonitor:
    def __init__(self, service):
        self.service = service
        self.lock = threading.Lock()

    def monitor(self):
        while True:
            with self.lock:
                for stream_id, stream in list(self.service.streams.items()):
                    if 'paused' not in stream:
                        # simulate connection monitoring
                        print(f"Monitoring connection for stream {stream_id}...")
                        time.sleep(1)

