        # Check if the video file exists
        if not os.path.exists(filename):
            return jsonify({'error': 'Video file not found'}), 404
        # Check if the video is being transcoded
        if is_transcoding(filename):
            return jsonify({'error': 'Video is being transcoded'}), 500
        # Start streaming
        return Response(stream_with_ffmpeg(filename), mimetype='video/mp4')
    else:
        return jsonify({'error': 'Video not found'}), 404

# Transcode video
def transcode_video(filename, resolution):
    # Create a temporary file for the transcoded video
    temp_filename = filename + '.tmp'
    # Transcode the video using ffmpeg
    ffmpeg.input(filename).output(temp_filename, vcodec='libx264', s=resolution).run()
    # Replace the original file with the transcoded file
    os.replace(temp_filename, filename)

# Check if the video is being transcoded
def is_transcoding(filename):
    # Check if a temporary file for the transcoded video exists
    return os.path.exists(filename + '.tmp')

# Get video resolution
def get_resolution(filename):
    # Use ffmpeg to get the video resolution
    probe = ffmpeg.probe(filename)
    width = probe['streams'][0]['width']
    height = probe['streams'][0]['height']
    return f'{width}x{height}'

# Stream video with ffmpeg
def stream_with_ffmpeg(filename):
    # Use ffmpeg to stream the video
    process = ffmpeg.input(filename).output('pipe:', format='mp4', vcodec='libx264').run_async(pipe_stdout=True)
    while True:
        stdout = process.stdout.read(1024)
        if not stdout:
            break
        yield stdout

