        self.videos[video_id] = video_data

    def get_video(self, video_id):
        return self.videos.get(video_id)

    def register_user(self, user_id):
        self.users[user_id] = {"watching": None, "paused": False, "position": 0}

    def start_watching(self, user_id, video_id):
        if video_id in self.videos:
            self.users[user_id]["watching"] = video_id
            self.users[user_id]["paused"] = False
            self.users[user_id]["position"] = 0

    def pause_video(self, user_id):
        if self.users[user_id]["watching"] is not None:
            self.users[user_id]["paused"] = True

    def resume_video(self, user_id):
        if self.users[user_id]["watching"] is not None:
            self.users[user_id]["paused"] = False

    def skip_forward(self, user_id, seconds):
        if self.users[user_id]["watching"] is not None:
            video_length = len(self.videos[self.users[user_id]["watching"]])
            new_position = self.users[user_id]["position"] + seconds
            if new_position < video_length:
                self.users[user_id]["position"] = new_position
            else:
                self.users[user_id]["position"] = video_length

    def skip_backward(self, user_id, seconds):
        if self.users[user_id]["watching"] is not None:
            new_position = self.users[user_id]["position"] - seconds
            if new_position >= 0:
                self.users[user_id]["position"] = new_position
            else:
                self.users[user_id]["position"] = 0

    def get_video_stream(self, user_id):
        if self.users[user_id]["watching"] is not None:
            video_id = self.users[user_id]["watching"]
            position = self.users[user_id]["position"]
            if self.users[user_id]["paused"]:
                return self.videos[video_id][position:]
            else:
                return self.videos[video_id][position:]

