        self.video = Video.query.get(video_id)
        self.resolution = self.video.resolution
        self.url = self.video.url
        self.streaming = False

    def start_stream(self):
        self.streaming = True
        threading.Thread(target=self.stream_video).start()

    def stream_video(self):
        while self.streaming:
            # stream video in chunks to handle large files
            with open(self.url, "rb") as f:
                while True:
                    chunk = f.read(1024 * 1024)  # read 1MB chunks
                    if not chunk:
                        break
                    yield chunk

    def pause_stream(self):
        self.streaming = False

    def resume_stream(self):
        self.streaming = True
        threading.Thread(target=self.stream_video).start()

    def skip_forwards(self, seconds):
        # seek to the desired position in the video
        with open(self.url, "rb") as f:
            f.seek(seconds * 1024 * 1024)  # assume 1MB per second

    def skip_backwards(self, seconds):
        # seek to the desired position in the video
        with open(self.url, "rb") as f:
            f.seek(-seconds * 1024 * 1024)  # assume 1MB per second

