import os
import threading
from flask import Flask, request, send_file, jsonify
from flask_cors import CORS
from werkzeug.utils import secure_filename
import ffmpeg

app = Flask(__name__)
CORS(app)

# Configuration
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'mp4', 'mkv', 'avi', 'mov'}
MAX_FILE_SIZE = 10 * 1024 * 1024 * 1024  # 10 GB

# Initialize upload folder
if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def generate_thumbnail(video_file):
    thumbnail_file = video_file.rsplit('.', 1)[0] + '.jpg'
    ffmpeg.input(video_file).output(thumbnail_file, vframes=1, q=2).run()
    return thumbnail_file

def transcode_video(video_file, resolution):
    output_file = video_file.rsplit('.', 1)[0] + '_' + resolution + '.mp4'
    ffmpeg.input(video_file).output(output_file, vcodec='libx264', acodec='aac', s=resolution).run()
    return output_file

@app.route('/upload', methods=['POST'])
def upload_file():
    if request.method == 'POST':
        file = request.files['file']
        if file and allowed_file(file.filename):
            filename = secure_filename(file.filename)
            file.save(os.path.join(UPLOAD_FOLDER, filename))
            thumbnail_file = generate_thumbnail(os.path.join(UPLOAD_FOLDER, filename))
            return jsonify({'filename': filename, 'thumbnail': thumbnail_file})

@app.route('/video/<filename>', methods=['GET'])
def get_video(filename):
    file_path = os.path.join(UPLOAD_FOLDER, filename)
    if os.path.exists(file_path):
        return send_file(file_path, mimetype='video/mp4')

@app.route('/thumbnail/<filename>', methods=['GET'])
def get_thumbnail(filename):
    file_path = os.path.join(UPLOAD_FOLDER, filename)
    if os.path.exists(file_path):
        return send_file(file_path, mimetype='image/jpeg')

@app.route('/transcode/<filename>/<resolution>', methods=['GET'])
def transcode(filename, resolution):
    file_path = os.path.join(UPLOAD_FOLDER, filename)
    if os.path.exists(file_path):
        output_file = transcode_video(file_path, resolution)
        return send_file(output_file, mimetype='video/mp4')

@app.route('/play/<filename>', methods=['GET'])
def play_video(filename):
    file_path = os.path.join(UPLOAD_FOLDER, filename)
    if os.path.exists(file_path):
        return send_file(file_path, mimetype='video/mp4', conditional=True)

@app.route('/seek/<filename>/<time>', methods=['GET'])
def seek_video(filename, time):
    file_path = os.path.join(UPLOAD_FOLDER, filename)
    if os.path.exists(file_path):
        return send_file(file_path, mimetype='video/mp4', conditional=True, start=int(time))

if __name__ == '__main__':
