class VideoStream:
    def __init__(self, video_file):
        self.video_file = video_file
        self.video_capture = cv2.VideoCapture(video_file)
        self.frame_rate = self.video_capture.get(cv2.CAP_PROP_FPS)
        self.width = int(self.video_capture.get(cv2.CAP_PROP_FRAME_WIDTH))
        self.height = int(self.video_capture.get(cv2.CAP_PROP_FRAME_HEIGHT))

    def get_frame(self, frame_number):
        self.video_capture.set(cv2.CAP_PROP_POS_FRAMES, frame_number)
        ret, frame = self.video_capture.read()
        if not ret:
            return None
        return frame

    def get_frame_at_time(self, time):
        frame_number = int(time * self.frame_rate)
        return self.get_frame(frame_number)

    def get_total_frames(self):
        return int(self.video_capture.get(cv2.CAP_PROP_FRAME_COUNT))

    def get_resolution(self):
        return (self.width, self.height)

    def get_duration(self):
        return self.get_total_frames() / self.frame_rate

