    def __init__(self, video_file, resolution):
        self.video_file = video_file
        self.resolution = resolution
        self.playing = False
        self.paused = False
        self.position = 0

    def play(self):
        if not self.playing:
            self.playing = True
            print("Video is playing")
        else:
            print("Video is already playing")

    def pause(self):
        if self.playing and not self.paused:
            self.paused = True
            print("Video is paused")
        else:
            print("Video is already paused or not playing")

    def resume(self):
        if self.paused:
            self.paused = False
            print("Video is resumed")
        else:
            print("Video is not paused")

    def skip_forward(self, seconds):
        if self.playing:
            self.position += seconds
            print(f"Video skipped forward {seconds} seconds")
        else:
            print("Video is not playing")

    def skip_backwards(self, seconds):
        if self.playing:
            self.position -= seconds
            if self.position < 0:
                self.position = 0
            print(f"Video skipped backwards {seconds} seconds")
        else:
            print("Video is not playing")

    def stop(self):
        if self.playing:
            self.playing = False
            self.paused = False
            self.position = 0
            print("Video is stopped")
        else:
            print("Video is already stopped")


