    def __repr__(self):
        return f"Video('{self.title}', '{self.filename}')"

def allowed_file(filename):
    return filename.split('.')[-1].lower() in ['mp4', 'avi', 'mkv']

def upload_video(file):
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file.save(os.path.join('uploads', filename))
        video = Video(title=request.form['title'], description=request.form['description'], filename=filename, resolution=request.form['resolution'], size=os.path.getsize(os.path.join('uploads', filename)))
        db.session.add(video)
        db.session.commit()
        return jsonify({'message': 'Video uploaded successfully'}), 201
    return jsonify({'message': 'Invalid file type'}), 400

def get_videos():
    videos = Video.query.all()
    output = []
    for video in videos:
        video_data = {'id': video.id, 'title': video.title, 'description': video.description, 'filename': video.filename, 'resolution': video.resolution, 'size': video.size}
        output.append(video_data)
    return jsonify({'videos': output})

def get_video(id):
    video = Video.query.get(id)
    if video:
        return send_file(os.path.join('uploads', video.filename))
    return jsonify({'message': 'Video not found'}), 404

