            self.stream.release()
            self.stream = None

    def get_frame(self):
        if self.stream:
            ret, frame = self.stream.read()
            return frame
        return None

    def pause_stream(self):
        if self.stream:
            self.stream.set(cv2.CAP_PROP_POS_FRAMES, self.stream.get(cv2.CAP_PROP_POS_FRAMES))

    def resume_stream(self):
        if self.stream:
            self.stream.set(cv2.CAP_PROP_POS_FRAMES, self.stream.get(cv2.CAP_PROP_POS_FRAMES) + 1)

    def skip_forward(self, seconds):
        if self.stream:
            self.stream.set(cv2.CAP_PROP_POS_MSEC, self.stream.get(cv2.CAP_PROP_POS_MSEC) + seconds * 1000)

    def skip_backward(self, seconds):
        if self.stream:
            self.stream.set(cv2.CAP_PROP_POS_MSEC, self.stream.get(cv2.CAP_PROP_POS_MSEC) - seconds * 1000)


