class VideoPlayer:
    def __init__(self):
        self.video_stream = None
        self.playing = False
        self.paused = False
        self.position = 0
        self.resolution = None
        self.buffer_size = 1024 * 1024  # 1MB buffer size

    def load_video(self, url):
        import requests
        self.video_stream = requests.get(url, stream=True)
        self.resolution = self.get_resolution()
        self.playing = True

    def get_resolution(self):
        import re
        content = self.video_stream.headers.get('Content-Type')
        match = re.search(r'resolution=(\d+x\d+)', content)
        if match:
            return match.group(1)
        else:
            return None

    def play(self):
        if not self.playing:
            self.playing = True
            self.paused = False
            self.position = 0
        else:
            self.paused = False

    def pause(self):
        if self.playing:
            self.paused = True

    def stop(self):
        self.playing = False
        self.paused = False
        self.position = 0

    def seek(self, position):
        if self.playing:
            self.position = position

    def forward(self, seconds):
        if self.playing:
            self.position += seconds

    def backward(self, seconds):
        if self.playing:
            self.position -= seconds

    def handle_connection(self, connection_speed):
        if connection_speed < 100000:  # 100kbps
            self.buffer_size = 512 * 1024  # 512KB buffer size
        elif connection_speed < 500000:  # 500kbps
            self.buffer_size = 1024 * 1024  # 1MB buffer size
        else:
            self.buffer_size = 2048 * 1024  # 2MB buffer size

    def handle_upload_download_size(self, size):
        if size > 100 * 1024 * 1024:  # 100MB
            print("Warning: Large file size may cause performance issues")

    def handle_concurrency(self, num_users):
        if num_users > 100:
            print("Warning: High concurrency may cause performance issues")

    def display_video(self):
        import cv2
        import numpy as np
        while self.playing:
            chunk = self.video_stream.raw.read(self.buffer_size)
            if not chunk:
                break
            chunk = np.frombuffer(chunk, dtype=np.uint8)
            frame = cv2.imdecode(chunk, cv2.IMREAD_COLOR)
            cv2.imshow('Video', frame)
            if cv2.waitKey(1) & 0xFF == ord('q'):
                break
        cv2.destroyAllWindows()

